//! native-pipeline-smoke — runs the WHOLE qwen-coder-7b inference pipeline
//! end-to-end as a single native (non-wasm, non-HTTP) binary.
//!
//! THE CRITICAL EXPERIMENT
//! -----------------------
//! The CF Worker mesh hits a panic inside `forward_range_attn_chunk` when
//! invoked through the wasm-bindgen wrapper. This binary calls the EXACT
//! same kernel functions on the EXACT same .knot, but bypasses both the
//! wasm boundary and the HTTP fluid-mesh transport.
//!
//! - native panics with the same error → bug is in the kernel itself
//! - native runs to completion           → bug is in wasm wrapping or transport
//!
//! Usage:
//!   cargo run --release --bin native-pipeline-smoke -- \
//!     /tmp/qwen-coder-7b.knot \
//!     "say hello in 5 words"
//!
//! Or with pre-tokenized IDs (decimal CSV) when no tokenizer is wired:
//!   cargo run --release --bin native-pipeline-smoke -- \
//!     /tmp/qwen-coder-7b.knot \
//!     --tokens 9707,11,1879,151643
//!
//! Steps mirror what apps/worker-node1/src/index.ts does inside the
//! liquid-mesh fluid forward path:
//!   1. mmap the knot via KnotWeights::load (uses MmapBackend underneath)
//!   2. NativeLlamaPipeline::from_knot(...) (no wasm wrapper)
//!   3. pipeline.embed_chunk(tokens, 0) → residual
//!   4. for layer in 0..num_layers:
//!        pipeline.forward_range_attn_chunk(input, layer, 0, seq_len, isFirst)
//!        pipeline.forward_range_ffn_gate_chunk(layer, seq_len)
//!        pipeline.forward_range_ffn_up_chunk(layer, seq_len)
//!        residual = pipeline.forward_range_ffn_down_chunk(layer, seq_len, isLast)
//!   5. logits = pipeline.lm_head_only(residual, seq_len)
//!   6. argmax → token id

use std::env;
use std::time::Instant;

use distributed_inference::loader::KnotWeights;
use distributed_inference::NativeLlamaPipeline;

fn main() -> Result<(), String> {
    let args: Vec<String> = env::args().collect();
    if args.len() < 3 {
        return Err(format!(
            "usage: {} <knot.path> [--tokens <csv>] [--max-layers <N>] <\"prompt or token csv\">",
            args.first()
                .map(String::as_str)
                .unwrap_or("native-pipeline-smoke")
        ));
    }

    let knot_path = args[1].clone();

    // Tokens may come either as the trailing arg ("a sentence", which we
    // hand-encode as a tiny stub if no tokenizer is wired) or via
    // --tokens 1,2,3 for pre-encoded IDs.
    let mut tokens: Vec<u32> = Vec::new();
    let mut max_layers: Option<usize> = None;
    let mut i = 2;
    while i < args.len() {
        match args[i].as_str() {
            "--tokens" => {
                i += 1;
                if i >= args.len() {
                    return Err("--tokens requires a CSV value".to_string());
                }
                for t in args[i].split(',') {
                    let v: u32 = t
                        .trim()
                        .parse()
                        .map_err(|e| format!("bad token id {t:?}: {e}"))?;
                    tokens.push(v);
                }
            }
            "--max-layers" => {
                i += 1;
                if i >= args.len() {
                    return Err("--max-layers requires a value".to_string());
                }
                let v: usize = args[i]
                    .parse()
                    .map_err(|e| format!("bad max-layers: {e}"))?;
                max_layers = Some(v);
            }
            _ => {
                // Trailing positional = prompt string. We don't have a
                // qwen2 tokenizer wired here — see the binary docstring.
                // For a stage-1 kernel test, ANY non-empty token sequence
                // exercises the same kernel paths the wasm panic hits, so
                // we fall back to a fixed BOS-ish stub if --tokens wasn't
                // provided. The kernel doesn't care about token semantics,
                // it cares about (seq_len, hidden_dim) shapes and whether
                // the layer math runs end-to-end.
                if tokens.is_empty() {
                    // Generic short qwen2 prompt-shaped stub. These IDs are
                    // safely inside the qwen2 vocab (151,936) and not BOS/PAD.
                    // For a real text round-trip, pass --tokens.
                    eprintln!(
                        "[native-pipeline-smoke] no --tokens given; using fixed 4-token stub for kernel exercise"
                    );
                    tokens = vec![9707, 11, 1879, 151643];
                }
            }
        }
        i += 1;
    }

    if tokens.is_empty() {
        return Err("no tokens to run; pass --tokens <csv> or a positional prompt".to_string());
    }

    println!("============================================================");
    println!(" native-pipeline-smoke");
    println!("   knot   : {}", knot_path);
    println!("   tokens : {:?}", tokens);
    println!("============================================================");

    // 1. Load knot via mmap (path-based, no HTTP, no wasm).
    println!("[1/6] mmap knot");
    let t0 = Instant::now();
    let knot = KnotWeights::load(&knot_path)?;
    let cfg_dump = knot
        .config
        .as_ref()
        .map(|c| {
            format!(
                "hidden_dim={} layers={} heads={} kv={} head_dim={} ffn={} vocab={} rope={}",
                c.hidden_dim,
                c.num_layers,
                c.num_heads,
                c.num_kv_heads,
                c.head_dim,
                c.intermediate_size,
                c.vocab_size,
                c.rope_theta,
            )
        })
        .unwrap_or_else(|| "(no config block — pipeline will use TinyLlama defaults)".to_string());
    println!(
        "       ok ({} ms)  tensors={}  config={}",
        t0.elapsed().as_millis(),
        knot.metadata.len(),
        cfg_dump
    );
    let num_layers = knot.config.as_ref().map(|c| c.num_layers).unwrap_or(22);
    let vocab_size = knot.config.as_ref().map(|c| c.vocab_size).unwrap_or(32000);
    let hidden_dim = knot.config.as_ref().map(|c| c.hidden_dim).unwrap_or(2048);
    let total_layers = max_layers.unwrap_or(num_layers).min(num_layers);

    // 2. Build the pipeline (NO wasm wrapper).
    println!("[2/6] NativeLlamaPipeline::from_knot");
    let t1 = Instant::now();
    let mut pipeline = NativeLlamaPipeline::from_knot(
        knot, /*draft_mode=*/ false, /*resonance_threshold=*/ 0.0,
    );
    println!("       ok ({} ms)", t1.elapsed().as_millis());

    // 3. Embed.
    let seq_len = tokens.len();
    println!(
        "[3/6] embed_chunk  seq_len={} hidden_dim={}",
        seq_len, hidden_dim
    );
    let t2 = Instant::now();
    let residual: Vec<f32> = pipeline.embed_chunk(&tokens, 0)?;
    let t_embed_ms = t2.elapsed().as_millis();
    let expected_emb = seq_len * hidden_dim;
    if residual.len() != expected_emb {
        return Err(format!(
            "embed_chunk returned {} floats; expected seq_len({}) * hidden_dim({}) = {}",
            residual.len(),
            seq_len,
            hidden_dim,
            expected_emb
        ));
    }
    let emb_min = residual.iter().cloned().fold(f32::INFINITY, f32::min);
    let emb_max = residual.iter().cloned().fold(f32::NEG_INFINITY, f32::max);
    println!(
        "       ok ({} ms)  out={} floats  range=[{:.4}, {:.4}]",
        t_embed_ms,
        residual.len(),
        emb_min,
        emb_max
    );

    // 4. Run all layers.
    println!(
        "[4/6] forward all layers  start_layer=0  end_layer={}  (model has {})",
        total_layers, num_layers
    );
    let mut layer_ms_total: u128 = 0;
    let mut last_layer_out: Vec<f32> = residual.clone();
    let start_pos = 0usize;

    for layer in 0..total_layers {
        let is_first = layer == 0;
        let is_last = layer == total_layers - 1;

        let lt = Instant::now();

        // Mirror the worker call sequence. On is_first, attn copies `input`
        // into batch_x; on subsequent layers we pass an empty slice because
        // batch_x carries the residual forward in-place.
        let attn_input: &[f32] = if is_first { &residual[..] } else { &[] };
        pipeline.forward_range_attn_chunk(attn_input, layer, start_pos, seq_len, is_first)?;
        pipeline.forward_range_ffn_gate_chunk(layer, seq_len)?;
        pipeline.forward_range_ffn_up_chunk(layer, seq_len)?;
        let out = pipeline.forward_range_ffn_down_chunk(layer, seq_len, is_last);

        let lms = lt.elapsed().as_millis();
        layer_ms_total += lms;

        // Get residual via get_residual for stats dump.
        let residual_now = pipeline.get_batch_x_residual(seq_len);
        let last_off = (seq_len - 1) * hidden_dim;
        let last_tok = &residual_now[last_off..last_off + hidden_dim];
        let max = last_tok.iter().fold(0.0f32, |a, &b| a.max(b.abs()));
        let mean = last_tok.iter().map(|&v| v.abs()).sum::<f32>() / last_tok.len() as f32;
        let sum_sq: f32 = last_tok.iter().map(|&v| v * v).sum();
        let rms = (sum_sq / last_tok.len() as f32).sqrt();

        if is_last {
            last_layer_out = out?;
        }
        // Print all layers for kernel-debug.
        println!(
            "       L{:>2}/{}: {} ms  last_tok max={:.3} mean={:.3} rms={:.3}  first8=[{:.3} {:.3} {:.3} {:.3} {:.3} {:.3} {:.3} {:.3}]",
            layer, total_layers, lms, max, mean, rms,
            last_tok[0], last_tok[1], last_tok[2], last_tok[3],
            last_tok[4], last_tok[5], last_tok[6], last_tok[7],
        );
    }
    println!(
        "       ok  total={} ms  avg/layer={:.1} ms",
        layer_ms_total,
        layer_ms_total as f64 / total_layers as f64
    );

    if total_layers != num_layers {
        println!(
            "[note] ran only {}/{} layers (--max-layers); skipping lm_head + argmax",
            total_layers, num_layers
        );
        return Ok(());
    }

    // 5. lm_head + final norm.
    println!(
        "[5/6] lm_head_only  seq_len={} vocab={}",
        seq_len, vocab_size
    );
    let t3 = Instant::now();
    let logits = pipeline.lm_head_only(&last_layer_out, seq_len)?;
    let t_lm_ms = t3.elapsed().as_millis();
    if logits.len() != vocab_size {
        return Err(format!(
            "lm_head_only returned {} logits; expected vocab_size {}",
            logits.len(),
            vocab_size
        ));
    }
    let lo = logits.iter().cloned().fold(f32::INFINITY, f32::min);
    let hi = logits.iter().cloned().fold(f32::NEG_INFINITY, f32::max);
    println!(
        "       ok ({} ms)  vocab={}  range=[{:.3}, {:.3}]",
        t_lm_ms,
        logits.len(),
        lo,
        hi
    );

    // 6. argmax + top-10.
    let (best_id, best_logit) =
        logits
            .iter()
            .enumerate()
            .fold((0usize, f32::NEG_INFINITY), |(bi, bv), (i, v)| {
                if *v > bv {
                    (i, *v)
                } else {
                    (bi, bv)
                }
            });
    println!(
        "[6/6] argmax token id = {}  (logit={:.4})",
        best_id, best_logit
    );

    // Dump residual (post-final-norm) so we can ship it to the mesh's lm_head
    // for parity comparison.
    if std::env::var("DUMP_RESIDUAL").is_ok() {
        let path = "/tmp/native-l27-residual.bin";
        let bytes = unsafe {
            std::slice::from_raw_parts(
                last_layer_out.as_ptr() as *const u8,
                last_layer_out.len() * 4,
            )
        };
        std::fs::write(path, bytes).expect("write residual");
        eprintln!(
            "[DUMP] wrote {} f32 floats ({} bytes) to {}",
            last_layer_out.len(),
            bytes.len(),
            path
        );
    }
    // Dump native's lm_head logits for parity testing.
    if std::env::var("DUMP_LOGITS").is_ok() {
        let path = "/tmp/native-l27-logits.bin";
        let bytes =
            unsafe { std::slice::from_raw_parts(logits.as_ptr() as *const u8, logits.len() * 4) };
        std::fs::write(path, bytes).expect("write logits");
        eprintln!(
            "[DUMP] wrote {} f32 logits ({} bytes) to {}",
            logits.len(),
            bytes.len(),
            path
        );
    }
    // Top-10
    let mut idx: Vec<usize> = (0..logits.len()).collect();
    idx.sort_by(|&a, &b| {
        logits[b]
            .partial_cmp(&logits[a])
            .unwrap_or(std::cmp::Ordering::Equal)
    });
    println!("       top-10:");
    for &i in idx.iter().take(10) {
        println!("         id={:6}  logit={:.4}", i, logits[i]);
    }
    // " Paris" rank
    let paris_rank = idx.iter().position(|&i| i == 12095).unwrap_or(usize::MAX);
    let the_rank = idx.iter().position(|&i| i == 576).unwrap_or(usize::MAX);
    println!(
        "       \" Paris\" (12095) rank={}, logit={:.4}",
        paris_rank, logits[12095]
    );
    println!(
        "       \" The\"   (576)   rank={}, logit={:.4}",
        the_rank, logits[576]
    );

    // Total wall.
    let total_ms = t0.elapsed().as_millis();
    let tps = 1000.0 / (total_ms as f64);
    println!(
        "\n[done] native pipeline ran end-to-end. wall={} ms  ({:.3} tok/s if this were one tok)",
        total_ms, tps
    );
    Ok(())
}
